<template><section class="space-y-6"><div><h1 class="text-3xl font-black text-slate-950 dark:text-white">Edge Developer Tools</h1><p class="text-slate-600 dark:text-slate-400">Signed edge registration, heartbeat, config fetch, and local ingest simulators.</p></div><div class="card grid gap-4 p-5 md:grid-cols-2"><TextInput v-model="edge.edgeId" :help="edgeIdHelp" /><SecretTextarea v-model="edge.token" :help="tokenHelp" /><TextareaInput v-model="body" :help="bodyHelp" /><div class="space-y-3"><button class="button-primary w-full" @click="register">Register edge</button><button class="button-secondary w-full" @click="heartbeat">Heartbeat</button><button class="button-secondary w-full" @click="config">Fetch config</button><button v-if="usageSimulator" class="button-secondary w-full" @click="usage">Usage ingest simulator</button><button v-if="usageSimulator" class="button-secondary w-full" @click="securityEvents">Security event ingest simulator</button></div></div><pre class="card overflow-auto p-5 text-xs">{{ JSON.stringify(result, null, 2) }}</pre></section></template>
<script setup lang="ts">
import { ref } from 'vue'; import TextInput from '@/components/forms/TextInput.vue'; import TextareaInput from '@/components/forms/TextareaInput.vue'; import SecretTextarea from '@/components/forms/SecretTextarea.vue'; import { useEdgeSessionStore } from '@/stores/edgeSession'; import { edgeSignedApi } from '@/lib/api/edgeSigned'; import { runtimeConfig } from '@/lib/config/env';
const edge = useEdgeSessionStore(); const usageSimulator = runtimeConfig.usageSimulator; const result = ref<unknown>(null); const body = ref('{\n  "status": "ok",\n  "version": "dev"\n}'); const parsedBody = () => JSON.parse(body.value || '{}');
const edgeIdHelp = { label: 'Edge ID', what: 'Registered edge node identifier.', works: 'Included in X-CDNLITE-Edge-Id and tied to the token.', example: 'edge-local-1', required: true }; const tokenHelp = { label: 'Edge token', what: 'Signed endpoint bearer token.', works: 'Session-memory only; used to derive the HMAC signing key.', example: 'edge-dev-token', required: true }; const bodyHelp = { label: 'JSON body', what: 'Payload for signed POST requests.', works: 'Body hash is included in the canonical signing string.', example: '{ "status": "ok" }' };
async function register() { result.value = await edgeSignedApi.register(edge.edgeId, edge.token, parsedBody()); } async function heartbeat() { result.value = await edgeSignedApi.heartbeat(edge.edgeId, edge.token, parsedBody()); } async function config() { result.value = await edgeSignedApi.config(edge.edgeId, edge.token); } async function usage() { result.value = await edgeSignedApi.usage(edge.edgeId, edge.token, parsedBody()); } async function securityEvents() { result.value = await edgeSignedApi.securityEvents(edge.edgeId, edge.token, parsedBody()); }
</script>
